const TERMINAL_TAB_AGENT_META = {
  claude: { color: "#d97757", label: "Claude Code", short: "CL" },
  codex: { color: "#7bdc9d", label: "Codex", short: "CX" },
  generic: { color: "#9fb6d9", label: "Terminal", short: ">_" },
  opencode: { color: "#68d8d6", label: "OpenCode", short: "OC" },
};

function getTerminalTabAgentMeta(role) {
  return TERMINAL_TAB_AGENT_META[String(role || "").toLowerCase()] || TERMINAL_TAB_AGENT_META.generic;
}

function normalizeTerminalFlamePlan(value, fallback = "free") {
  const key = String(value || "").trim().toLowerCase();
  if (TERMINAL_FLAME_PLAN_KEYS.has(key)) {
    return key;
  }
  const fallbackKey = String(fallback || "").trim().toLowerCase();
  return TERMINAL_FLAME_PLAN_KEYS.has(fallbackKey) ? fallbackKey : "free";
}

function terminalBillingPlanNameFromStatus(billingStatus, fallback = "free") {
  const rawPlan = String(
    billingStatus?.planName
      || billingStatus?.plan_name
      || billingStatus?.credits?.planName
      || billingStatus?.credits?.plan_name
      || "",
  ).trim().toLowerCase();
  if (TERMINAL_FLAME_PLAN_KEYS.has(rawPlan)) {
    return rawPlan;
  }

  const status = String(
    billingStatus?.planStatus || billingStatus?.plan_status || "",
  ).trim().toLowerCase();
  return status === "paid" ? "plus" : fallback;
}

function TerminalEmptyAgentLauncherGlyph({ role_id: roleId }) {
  if (roleId === "codex") {
    return <WorkspaceCreateAgentCodexIcon aria-hidden="true" />;
  }
  if (roleId === "claude") {
    return <WorkspaceCreateAgentClaudeIcon aria-hidden="true" />;
  }
  if (roleId === "opencode") {
    return (
      <WorkspaceCreateAgentOpenCodeIcon
        aria-hidden="true"
        fill="none"
        viewBox="0 0 24 30"
        xmlns="http://www.w3.org/2000/svg"
      >
        <path d="M18 24H6V12H18V24Z" fill="#4B4646" />
        <path d="M18 6H6V24H18V6ZM24 30H0V0H24V30Z" fill="#F1ECEC" />
      </WorkspaceCreateAgentOpenCodeIcon>
    );
  }
  return <WorkspaceCreateAgentTerminalIcon aria-hidden="true" />;
}

function TerminalToolboxPanelGlyph({ panel_id: panelId }) {
  if (panelId === "web") {
    return <DeviceWebIcon aria-hidden="true" />;
  }
  if (panelId === "docs") {
    return <FileDocumentIcon aria-hidden="true" />;
  }
  if (panelId === "pcb") {
    return <ButtonProcessIcon aria-hidden="true" />;
  }
  if (panelId === "vm") {
    return <DeviceComputerIcon aria-hidden="true" />;
  }
  if (panelId === "video") {
    return <Movie aria-hidden="true" />;
  }
  if (panelId === "swarm") {
    return <SwarmPanelIcon aria-hidden="true" />;
  }
  return <ButtonHubIcon aria-hidden="true" />;
}

function TerminalEmptyPanelLauncherGlyph({ panel_id: panelId }) {
  return <TerminalToolboxPanelGlyph panel_id={panelId} />;
}

