/* One green pulse confirming a drop (snip preview or OS file) was accepted
   by the target under the cursor. */
const todoDropAcceptFlash = keyframes`
  0% { opacity: 0; }
  12% { opacity: 1; }
  100% { opacity: 0; }
`;

const TerminalSurfaceSlot = styled.div`
  position: absolute;
  top: 0;
  left: 0;
  z-index: var(--terminal-slot-z, 1);
  width: var(--terminal-slot-width, 0px);
  height: var(--terminal-slot-height, 0px);
  min-width: 0;
  min-height: 0;
  overflow: visible;
  background: #020304;
  contain: layout style;
  pointer-events: auto;
  /* 2D translate at rest: translate3d (like will-change) forces a permanent
     compositing layer per slot — the second timeline recording proved
     removing will-change alone left compositing flat (~4s/26s, 108ms/frame).
     Interaction states below restore translate3d for compositor-driven
     movement while dragging/breaking out. */
  transform: translate(var(--terminal-slot-x, 0px), var(--terminal-slot-y, 0px)) scale(var(--terminal-slot-scale, 1));
  transform-origin: 0 0;
  /* Never transition width/height: animating the slot box re-layouts every
     frame, so each pane's ResizeObserver fires per frame and xterm reflows
     its whole scrollback repeatedly during maximize/restore. Sizes snap;
     only transform (position/scale) and paint-only properties animate. */
  transition:
    transform 170ms cubic-bezier(0.2, 0.8, 0.2, 1),
    filter 140ms ease,
    opacity 140ms ease;
  /* Layer diet: permanent will-change promoted EVERY slot to its own GPU
     layer — timeline profiling measured compositing at ~61ms per frame (4s
     of a 26s recording). At rest slots stay unpromoted; promotion applies
     only while dragging, and WebKit auto-promotes for
     the duration of the transform transition. */
  will-change: auto;

  &[data-terminal-tab-hidden="true"] {
    visibility: hidden;
    pointer-events: none;
  }

  &[data-terminal-dragging="true"],
  [data-terminal-grid-dragging="true"] & {
    transform: translate3d(var(--terminal-slot-x, 0px), var(--terminal-slot-y, 0px), 0) scale(var(--terminal-slot-scale, 1));
    will-change: transform;
  }

  &[data-terminal-dragging="true"] {
    transition: none;
  }

  html[data-forge-theme="light"] & {
    background: #ffffff;
  }

  &[data-terminal-hidden="true"] {
    visibility: hidden;
    pointer-events: none;
  }

  &[data-terminal-dragging="true"] {
    z-index: 260;
    pointer-events: none;
    transition: none;
    filter: drop-shadow(0 28px 48px rgba(0, 0, 0, 0.46));
  }

  &[data-terminal-dragging="true"] > * {
    transform: scale(1.012);
    transform-origin: center;
  }

  &[data-terminal-fullscreen="true"] {
    z-index: 240;
  }

  /* A dragged snip preview window or OS file is hovering this terminal. */
  &[data-snip-drop-active="true"]::after {
    content: "";
    position: absolute;
    inset: 0;
    z-index: 90;
    pointer-events: none;
    box-shadow:
      inset 0 0 0 2px rgba(74, 222, 128, 0.85),
      inset 0 0 22px rgba(74, 222, 128, 0.2);
  }

  /* A drop just landed here. */
  &[data-drop-flash="true"]::after {
    content: "";
    position: absolute;
    inset: 0;
    z-index: 90;
    pointer-events: none;
    box-shadow:
      inset 0 0 0 2px rgba(74, 222, 128, 0.95),
      inset 0 0 30px rgba(74, 222, 128, 0.32);
    animation: ${todoDropAcceptFlash} 900ms ease-out forwards;
  }
`;

