const OrchestratorTopButton = styled.button`
  display: inline-flex;
  flex: 1 1 auto;
  min-width: 0;
  align-items: center;
  justify-content: center;
  padding: 0 6px;
  border: 0;
  border-right: 1px solid rgba(230, 236, 245, 0.07);
  color: #9eabbc;
  background: transparent;
  cursor: pointer;
  font-size: 11px;
  font-weight: 780;
  line-height: 1;
  outline: none;
  transition:
    background 220ms ease,
    border-color 220ms ease,
    color 220ms ease,
    opacity 140ms ease;
  white-space: nowrap;

  span {
    display: block;
    min-width: 0;
    overflow: hidden;
    text-overflow: ellipsis;
  }

  [data-label="compact"] {
    display: none;
  }

  &:last-child {
    border-right: 0;
  }

  &[data-active="true"] {
    color: #f7fafc;
    background:
      linear-gradient(180deg, rgba(var(--forge-tint-rgb), 0.08), rgba(var(--forge-tint-rgb), 0.035)),
      rgba(8, 12, 18, 0.48);
  }

  &:disabled {
    cursor: default;
    opacity: 0.4;
  }

  &:not(:disabled):hover {
    color: #f7fafc;
    background:
      linear-gradient(180deg, rgba(var(--forge-tint-rgb), 0.09), rgba(var(--forge-tint-rgb), 0.04)),
      rgba(8, 12, 18, 0.5);
  }

  html[data-forge-theme="light"] & {
    border-right-color: rgba(0, 0, 0, 0.07);
    color: #333333;
  }

  html[data-forge-theme="light"] &[data-active="true"],
  html[data-forge-theme="light"] &:not(:disabled):hover {
    color: var(--forge-tint);
    background: rgba(var(--forge-tint-rgb), 0.045);
  }

  /* Compact labels engage before full labels would start truncating with
     all five tabs sharing one row. */
  @container (max-width: 372px) {
    [data-label="full"][data-has-compact="true"] {
      display: none;
    }

    [data-label="compact"] {
      display: block;
    }
  }
`;

