const OrchestratorVoiceButton = styled.button`
  display: grid;
  position: relative;
  isolation: isolate;
  box-sizing: border-box;
  width: 58px;
  height: 58px;
  padding: 0;
  place-items: center;
  border: 1px solid rgba(255, 255, 255, 0.1);
  border-radius: 999px;
  background: #000000;
  box-shadow: 0 0 0 4px rgba(244, 247, 250, 0.1);
  cursor: pointer;
  line-height: 0;
  outline: none;
  overflow: visible;
  transition:
    border-color 150ms ease,
    box-shadow 150ms ease,
    transform 150ms ease;
  appearance: none;
  -webkit-appearance: none;

  &::before {
    position: absolute;
    inset: 0;
    z-index: 0;
    border-radius: inherit;
    background:
      radial-gradient(circle, rgba(var(--forge-tint-soft-rgb), 0.11), transparent 62%),
      radial-gradient(circle, rgba(217, 121, 53, 0.05), transparent 76%);
    content: "";
    opacity: 0;
    transform: scale(0.92);
    transition:
      opacity 160ms ease,
      transform 170ms cubic-bezier(0.2, 0.8, 0.2, 1);
    pointer-events: none;
  }

  html[data-forge-theme="light"] &::before {
    background:
      radial-gradient(circle, rgba(var(--forge-tint-rgb), 0.075), transparent 62%),
      radial-gradient(circle, rgba(221, 112, 31, 0.045), transparent 76%);
  }

  &:hover {
    border-color: rgba(var(--forge-tint-soft-rgb), 0.26);
    box-shadow: 0 0 0 4px rgba(var(--forge-tint-soft-rgb), 0.09);
  }

  &:active {
    transform: scale(0.98);
  }

  &[data-monitoring="true"] {
    border-color: rgba(var(--forge-tint-soft-rgb), 0.3);
    box-shadow:
      0 0 0 4px rgba(var(--forge-tint-soft-rgb), 0.08),
      0 0 0 1px rgba(var(--forge-tint-soft-rgb), 0.1) inset;
  }

  &[data-monitoring="true"]::before {
    opacity: 1;
    transform: scale(1);
  }

  &[data-starting="true"] {
    cursor: progress;
  }

  &[data-starting="true"]::after {
    position: absolute;
    z-index: 6;
    width: 24px;
    height: 24px;
    border: 2px solid rgba(244, 247, 250, 0.28);
    border-top-color: rgba(244, 247, 250, 0.96);
    border-radius: 999px;
    content: "";
    animation: ${orchestratorVoiceButtonSpin} 760ms linear infinite;
    pointer-events: none;
  }

  &[data-starting="true"] img {
    opacity: 0.42;
  }

  &:disabled {
    cursor: progress;
  }

  &[data-error="true"] {
    border-color: rgba(239, 68, 68, 0.52);
    box-shadow:
      0 0 0 4px rgba(239, 68, 68, 0.1),
      0 0 24px rgba(239, 68, 68, 0.12);
  }

  html[data-forge-theme="light"] & {
    border-color: rgba(255, 255, 255, 0.16);
    background: #000000;
    box-shadow: 0 0 0 4px rgba(0, 0, 0, 0.08);
  }

  html[data-forge-theme="light"] &:hover {
    border-color: rgba(255, 255, 255, 0.22);
    box-shadow: 0 0 0 4px rgba(var(--forge-tint-rgb), 0.065);
  }

  html[data-forge-theme="light"] &[data-monitoring="true"] {
    border-color: rgba(255, 255, 255, 0.36);
    box-shadow:
      0 0 0 4px rgba(var(--forge-tint-rgb), 0.06),
      0 0 0 1px rgba(var(--forge-tint-rgb), 0.08) inset;
  }
`;

