const LoopspaceTriggersPanel = memo(function LoopspaceTriggersPanel() {
  const [triggers, setTriggers] = useState([]);
  const [loopspaces, setLoopspaces] = useState([]);
  const [state, setState] = useState("idle");
  const [error, setError] = useState("");
  const [draftName, setDraftName] = useState("");
  const [draftType, setDraftType] = useState("cron");
  const [draftWebhookAuthMode, setDraftWebhookAuthMode] = useState("signed_hmac");
  const [draftPublicWebhookConfirmed, setDraftPublicWebhookConfirmed] = useState(false);
  const [draftSchedulePreset, setDraftSchedulePreset] = useState("5m");
  const [draftCustomSchedule, setDraftCustomSchedule] = useState("");
  const [nameDrafts, setNameDrafts] = useState({});
  const [editingTriggerId, setEditingTriggerId] = useState("");
  const [copiedTriggerId, setCopiedTriggerId] = useState("");
  const [webhookBaseUrl, setWebhookBaseUrl] = useState("");
  const editingTriggerIdRef = useRef("");
  const editingNameInputRef = useRef(null);
  const copyFeedbackTimeoutRef = useRef(null);

  const applyTriggerSnapshot = useCallback((value) => {
    const snapshot = normalizeLoopspaceTriggerSnapshot(value);
    const editingId = editingTriggerIdRef.current;
    setTriggers(snapshot.triggers);
    if (editingId && !snapshot.triggers.some((trigger) => trigger.id === editingId)) {
      editingTriggerIdRef.current = "";
      setEditingTriggerId("");
    }
    setNameDrafts((current) => {
      const next = {};
      for (const trigger of snapshot.triggers) {
        next[trigger.id] = trigger.id === editingId && Object.prototype.hasOwnProperty.call(current, trigger.id)
          ? current[trigger.id]
          : trigger.name;
      }
      return next;
    });
    return snapshot;
  }, []);

  const applyLoopspaceSnapshot = useCallback((value) => {
    const rows = normalizeLoopspaceRows(value);
    setLoopspaces(rows);
    return rows;
  }, []);

  const syncLoopspaces = useCallback(async () => {
    try {
      applyLoopspaceSnapshot(await invoke("cloud_mcp_get_loopspaces"));
    } catch {
      applyLoopspaceSnapshot([]);
    }
    try {
      applyLoopspaceSnapshot(await invoke("cloud_mcp_sync_loopspaces"));
    } catch {
      // A trigger can still be created without loop attachments.
    }
  }, [applyLoopspaceSnapshot]);

  const syncTriggers = useCallback(async (remote = true) => {
    setState("loading");
    setError("");
    try {
      applyTriggerSnapshot(await invoke("cloud_mcp_get_loopspace_triggers"));
    } catch {
      applyTriggerSnapshot({});
    }
    if (!remote) {
      setState("idle");
      return;
    }
    try {
      applyTriggerSnapshot(await invoke("cloud_mcp_sync_loopspace_triggers"));
      setState("idle");
    } catch (syncError) {
      setState("idle");
      setError(String(syncError || "Unable to sync triggers."));
    }
  }, [applyTriggerSnapshot]);

  useEffect(() => {
    syncTriggers(true);
    syncLoopspaces();
  }, [syncLoopspaces, syncTriggers]);

  useEffect(() => {
    let disposed = false;
    void invoke("cloud_mcp_get_status").then((status) => {
      if (disposed) return;
      setWebhookBaseUrl(String(status?.base_url || "").trim());
    }).catch(() => {});
    return () => {
      disposed = true;
    };
  }, []);

  useEffect(() => () => {
    if (copyFeedbackTimeoutRef.current) {
      window.clearTimeout(copyFeedbackTimeoutRef.current);
      copyFeedbackTimeoutRef.current = null;
    }
  }, []);

  useEffect(() => {
    if (!editingTriggerId || !editingNameInputRef.current) {
      return undefined;
    }
    const node = editingNameInputRef.current;
    const focusNameInput = () => {
      node.focus();
      node.select();
    };
    if (typeof window !== "undefined" && typeof window.requestAnimationFrame === "function") {
      const frameId = window.requestAnimationFrame(focusNameInput);
      return () => window.cancelAnimationFrame(frameId);
    }
    focusNameInput();
    return undefined;
  }, [editingTriggerId]);

  useEffect(() => {
    let disposed = false;
    const unsubscribe = listenShared(CLOUD_MCP_LOOPSPACE_TRIGGERS_UPDATED_EVENT, (event) => {
      if (!disposed) {
        applyTriggerSnapshot(event?.payload || event);
      }
    });
    return () => {
      disposed = true;
      unsubscribe();
    };
  }, [applyTriggerSnapshot]);

  const loopspaceById = useMemo(() => {
    const map = new Map();
    for (const loopspace of loopspaces) {
      map.set(loopspace.id, loopspace);
    }
    return map;
  }, [loopspaces]);

  const draftSchedule = useMemo(() => {
    const preset = LOOPSPACE_TRIGGER_SCHEDULE_PRESETS.find((option) => option.id === draftSchedulePreset);
    if (preset?.value) {
      return preset.value;
    }
    return draftCustomSchedule.trim() || "@every 5m";
  }, [draftCustomSchedule, draftSchedulePreset]);

  const createTrigger = useCallback(async (event) => {
    event.preventDefault();
    const name = draftName.trim();
    if (!name) {
      setError("Trigger name is required.");
      return;
    }
    if (draftType === "webhook" && draftWebhookAuthMode === "public_token" && !draftPublicWebhookConfirmed) {
      setError("Confirm the public URL risk before creating this webhook.");
      return;
    }
    const config = draftType === "cron"
      ? {
        schedule: draftSchedule.trim() || "@every 5m",
      }
      : {};
    setState("saving");
    setError("");
    try {
      const result = await invoke("cloud_mcp_create_loopspace_trigger", {
        config,
        enabled: true,
        loopspace_ids: [],
        name,
        public_webhook_confirmed: draftType === "webhook" && draftWebhookAuthMode === "public_token"
          ? draftPublicWebhookConfirmed
          : undefined,
        trigger_type: draftType,
        webhook_auth_mode: draftType === "webhook" ? draftWebhookAuthMode : undefined,
        webhook_signature_tolerance_sec: draftType === "webhook" ? 300 : undefined,
      });
      applyTriggerSnapshot(result);
      setDraftName("");
      setDraftPublicWebhookConfirmed(false);
      setState("idle");
    } catch (createError) {
      setState("idle");
      setError(String(createError || "Unable to create trigger."));
    }
  }, [
    applyTriggerSnapshot,
    draftName,
    draftPublicWebhookConfirmed,
    draftSchedule,
    draftWebhookAuthMode,
    draftType,
  ]);

  const beginRenameTrigger = useCallback((trigger) => {
    if (!trigger?.id || state === "saving") {
      return;
    }
    setNameDrafts((current) => ({
      ...current,
      [trigger.id]: String(current[trigger.id] ?? trigger.name),
    }));
    editingTriggerIdRef.current = trigger.id;
    setEditingTriggerId(trigger.id);
  }, [state]);

  const cancelRenameTrigger = useCallback((trigger) => {
    if (!trigger?.id) {
      return;
    }
    setNameDrafts((current) => ({
      ...current,
      [trigger.id]: trigger.name,
    }));
    editingTriggerIdRef.current = "";
    setEditingTriggerId("");
    setError("");
  }, []);

  const renameTrigger = useCallback(async (trigger) => {
    if (!trigger?.id || state === "saving") {
      return;
    }
    const name = String(nameDrafts[trigger.id] ?? trigger.name).trim();
    if (!name) {
      setError("Trigger name is required.");
      return;
    }
    if (name === trigger.name) {
      setNameDrafts((current) => ({
        ...current,
        [trigger.id]: trigger.name,
      }));
      editingTriggerIdRef.current = "";
      setEditingTriggerId("");
      return;
    }
    setState("saving");
    setError("");
    try {
      applyTriggerSnapshot(await invoke("cloud_mcp_update_loopspace_trigger", {
        name,
        trigger_id: trigger.id,
      }));
      editingTriggerIdRef.current = "";
      setEditingTriggerId("");
      setState("idle");
    } catch (renameError) {
      setState("idle");
      setError(String(renameError || "Unable to rename trigger."));
    }
  }, [applyTriggerSnapshot, nameDrafts, state]);

  const toggleTriggerEnabled = useCallback(async (trigger) => {
    if (!trigger?.id || state === "saving") {
      return;
    }
    setState("saving");
    setError("");
    try {
      applyTriggerSnapshot(await invoke("cloud_mcp_update_loopspace_trigger", {
        enabled: !trigger.enabled,
        trigger_id: trigger.id,
      }));
      setState("idle");
    } catch (toggleError) {
      setState("idle");
      setError(String(toggleError || "Unable to update trigger."));
    }
  }, [applyTriggerSnapshot, state]);

  const copyWebhookTrigger = useCallback(async (trigger, webhookUrl) => {
    const copyValue = String(webhookUrl || "").trim();
    if (!trigger?.id || !copyValue) {
      return;
    }
    setError("");
    try {
      const copied = await copyTextToClipboard(copyValue);
      if (!copied) {
        throw new Error("Clipboard unavailable.");
      }
      setCopiedTriggerId(trigger.id);
      if (copyFeedbackTimeoutRef.current) {
        window.clearTimeout(copyFeedbackTimeoutRef.current);
      }
      copyFeedbackTimeoutRef.current = window.setTimeout(() => {
        setCopiedTriggerId((current) => (current === trigger.id ? "" : current));
        copyFeedbackTimeoutRef.current = null;
      }, 1300);
    } catch (copyError) {
      setError(String(copyError || "Unable to copy webhook URL."));
    }
  }, []);

  const copyWebhookSecret = useCallback(async (trigger) => {
    const copyValue = String(trigger?.webhook_secret || "").trim();
    if (!trigger?.id || !copyValue) {
      return;
    }
    setError("");
    try {
      const copied = await copyTextToClipboard(copyValue);
      if (!copied) {
        throw new Error("Clipboard unavailable.");
      }
      setCopiedTriggerId(`${trigger.id}:secret`);
      if (copyFeedbackTimeoutRef.current) {
        window.clearTimeout(copyFeedbackTimeoutRef.current);
      }
      copyFeedbackTimeoutRef.current = window.setTimeout(() => {
        setCopiedTriggerId((current) => (current === `${trigger.id}:secret` ? "" : current));
        copyFeedbackTimeoutRef.current = null;
      }, 1300);
    } catch (copyError) {
      setError(String(copyError || "Unable to copy webhook signing secret."));
    }
  }, []);

  const rotateWebhookSecret = useCallback(async (trigger) => {
    if (!trigger?.id || trigger.type !== "webhook" || state === "saving") {
      return;
    }
    const label = trigger.webhook_auth_mode === "public_token" ? "public URL token" : "signing secret";
    const confirmed = typeof window === "undefined"
      ? true
      : window.confirm(`Rotate the ${label} for "${trigger.name}"? Existing integrations will need to be updated.`);
    if (!confirmed) {
      return;
    }
    setState("saving");
    setError("");
    try {
      applyTriggerSnapshot(await invoke("cloud_mcp_update_loopspace_trigger", {
        rotate_secret: true,
        trigger_id: trigger.id,
      }));
      setState("idle");
    } catch (rotateError) {
      setState("idle");
      setError(String(rotateError || "Unable to rotate webhook secret."));
    }
  }, [applyTriggerSnapshot, state]);

  const runTrigger = useCallback(async (trigger) => {
    if (!trigger?.id || trigger.type !== "manual" || !trigger.enabled || state === "saving") {
      return;
    }
    setState("saving");
    setError("");
    try {
      applyTriggerSnapshot(await invoke("cloud_mcp_run_loopspace_trigger", {
        payload: {},
        source: "rust-diffforge-ui",
        trigger_id: trigger.id,
      }));
      setState("idle");
    } catch (runError) {
      setState("idle");
      setError(String(runError || "Unable to run trigger."));
    }
  }, [applyTriggerSnapshot, state]);

  const deleteTrigger = useCallback(async (trigger) => {
    if (!trigger?.id || state === "saving") {
      return;
    }
    const confirmed = typeof window === "undefined"
      ? true
      : window.confirm(`Delete "${trigger.name}"?`);
    if (!confirmed) {
      return;
    }
    setState("saving");
    setError("");
    try {
      applyTriggerSnapshot(await invoke("cloud_mcp_delete_loopspace_trigger", {
        trigger_id: trigger.id,
      }));
      setState("idle");
    } catch (deleteError) {
      setState("idle");
      setError(String(deleteError || "Unable to delete trigger."));
    }
  }, [applyTriggerSnapshot, state]);

  const startTriggerDrag = useCallback((event, trigger) => {
    if (!trigger?.id) {
      event.preventDefault();
      return;
    }
    const target = event.target;
    if (
      typeof HTMLElement !== "undefined"
      && target instanceof HTMLElement
      && (
        target.closest("button,textarea,select")
        || (target.closest("input") && !target.closest("input")?.readOnly)
      )
    ) {
      event.preventDefault();
      return;
    }
    const payload = JSON.stringify({
      kind: LOOPSPACE_TRIGGER_DRAG_KIND,
      id: trigger.id,
      loopspace_ids: trigger.loopspace_ids || [],
      name: trigger.name,
      trigger_id: trigger.id,
      type: trigger.type,
      trigger_type: trigger.type,
    });
    event.dataTransfer.effectAllowed = "copy";
    try {
      event.dataTransfer.setData("text/plain", payload);
    } catch {
      try {
        event.dataTransfer.setData("text/plain", trigger.id);
      } catch {
        // Some embedded targets reject data writes; custom MIME remains best-effort.
      }
    }
    try {
      event.dataTransfer.setData(LOOPSPACE_TRIGGER_DRAG_MIME, payload);
    } catch {
      // text/plain is the cross-webview path.
    }
  }, []);

  const startTriggerPointerDrag = useCallback((event, trigger) => {
    if (event.button !== 0 || !trigger?.id) return;
    const target = event.target;
    if (
      typeof HTMLElement !== "undefined"
      && target instanceof HTMLElement
      && (
        target.closest("button,textarea,select")
        || (target.closest("input") && !target.closest("input")?.readOnly)
      )
    ) {
      return;
    }
    event.preventDefault();
    event.stopPropagation();
    if (typeof window === "undefined" || typeof CustomEvent === "undefined") return;
    window.dispatchEvent(new CustomEvent(LOOPSPACE_GRAPH_POINTER_DRAG_EVENT, {
      detail: {
        kind: "trigger",
        pointer_id: event.pointerId,
        trigger: {
          id: trigger.id,
          loopspace_ids: trigger.loopspace_ids || [],
          name: trigger.name,
          trigger_id: trigger.id,
          trigger_type: trigger.type,
          type: trigger.type,
        },
      },
    }));
  }, []);

  return (
    <LoopspaceTriggersView>
      <LoopspaceTriggersScroll>
        <LoopspaceTriggerForm onSubmit={createTrigger}>
          <LoopspaceTriggerFieldGrid>
            <LoopspaceTriggerInput
              aria-label="Trigger name"
              maxLength={120}
              onChange={(event) => setDraftName(event.target.value)}
              placeholder="Trigger name"
              value={draftName}
            />
          </LoopspaceTriggerFieldGrid>
          <LoopspaceTriggerTypePicker aria-label="Trigger type" role="group">
            {LOOPSPACE_TRIGGER_TYPE_OPTIONS.map((option) => {
              const Icon = option.icon;
              return (
                <LoopspaceTriggerTypeButton
                  data-active={draftType === option.value}
                  key={option.value}
                  onClick={() => {
                    setDraftType(option.value);
                    if (option.value !== "webhook") {
                      setDraftPublicWebhookConfirmed(false);
                    }
                  }}
                  type="button"
                >
                  <Icon aria-hidden="true" />
                  <span>{option.label}</span>
                </LoopspaceTriggerTypeButton>
              );
            })}
          </LoopspaceTriggerTypePicker>
          {draftType === "cron" ? (
            <>
              <LoopspaceTriggerSectionLabel>Schedule</LoopspaceTriggerSectionLabel>
              <LoopspaceTriggerTypePicker aria-label="Cron schedule" data-variant="schedule" role="group">
                {LOOPSPACE_TRIGGER_SCHEDULE_PRESETS.map((option) => (
                  <LoopspaceTriggerTypeButton
                    data-active={draftSchedulePreset === option.id}
                    data-schedule-id={option.id}
                    data-variant="schedule"
                    key={option.id}
                    onClick={() => setDraftSchedulePreset(option.id)}
                    type="button"
                  >
                    {option.label}
                  </LoopspaceTriggerTypeButton>
                ))}
              </LoopspaceTriggerTypePicker>
              {draftSchedulePreset === "custom" ? (
                <LoopspaceTriggerInput
                  aria-label="Custom cron schedule"
                  onChange={(event) => setDraftCustomSchedule(event.target.value)}
                  placeholder="@every 5m"
                  value={draftCustomSchedule}
                />
              ) : null}
            </>
          ) : null}
          {draftType === "webhook" ? (
            <>
              <LoopspaceTriggerSectionLabel>Webhook security</LoopspaceTriggerSectionLabel>
              <LoopspaceTriggerTypePicker aria-label="Webhook security mode" data-variant="webhook-auth" role="group">
                {LOOPSPACE_WEBHOOK_AUTH_OPTIONS.map((option) => (
                  <LoopspaceTriggerTypeButton
                    data-active={draftWebhookAuthMode === option.value}
                    data-variant="webhook-auth"
                    key={option.value}
                    onClick={() => {
                      setDraftWebhookAuthMode(option.value);
                      if (option.value !== "public_token") {
                        setDraftPublicWebhookConfirmed(false);
                      }
                    }}
                    type="button"
                  >
                    {option.label}
                  </LoopspaceTriggerTypeButton>
                ))}
              </LoopspaceTriggerTypePicker>
              <LoopspaceWebhookModeHelp data-tone={draftWebhookAuthMode === "public_token" ? "risk" : "safe"}>
                {draftWebhookAuthMode === "public_token"
                  ? "Anyone with this URL can fire the trigger."
                  : "Signed requests must include a Stripe-style HMAC timestamp header."}
              </LoopspaceWebhookModeHelp>
              {draftWebhookAuthMode === "public_token" ? (
                <LoopspaceWebhookConfirm>
                  <input
                    checked={draftPublicWebhookConfirmed}
                    onChange={(event) => setDraftPublicWebhookConfirmed(event.target.checked)}
                    type="checkbox"
                  />
                  <span>I understand this public URL is a bearer credential.</span>
                </LoopspaceWebhookConfirm>
              ) : null}
            </>
          ) : null}
          <LoopspaceTriggerActionRow>
            <LoopspaceTriggerPrimaryButton
              disabled={
                state === "saving"
                || !draftName.trim()
                || (draftType === "webhook" && draftWebhookAuthMode === "public_token" && !draftPublicWebhookConfirmed)
              }
              title="Create trigger"
              type="submit"
            >
              <ButtonAddIcon aria-hidden="true" />
              <span>Create</span>
            </LoopspaceTriggerPrimaryButton>
          </LoopspaceTriggerActionRow>
          {error ? <LoopspaceTriggersMeta role="status">{error}</LoopspaceTriggersMeta> : null}
        </LoopspaceTriggerForm>
        {triggers.length > 0 ? (
          <LoopspaceTriggerList>
            {triggers.map((trigger) => {
              const attachedLoops = trigger.loopspace_ids
                .map((id) => loopspaceById.get(id)?.name || id)
                .filter(Boolean);
              const nextDue = formatLoopspaceTriggerTime(trigger.next_due_at_ms);
              const lastRun = formatLoopspaceTriggerTime(trigger.last_run_at_ms);
              const isRenaming = editingTriggerId === trigger.id;
              const webhookUrl = trigger.webhook_path
                ? getLoopspaceWebhookCopyUrl(trigger.webhook_path, webhookBaseUrl)
                : "";
              const isWebhookCopied = copiedTriggerId === trigger.id;
              const isWebhookSecretCopied = copiedTriggerId === `${trigger.id}:secret`;
              const TypeIcon = getLoopspaceTriggerTypeIcon(trigger.type);
              return (
                <LoopspaceTriggerRow
                  key={trigger.id}
                  onDragStart={(event) => startTriggerDrag(event, trigger)}
                  onPointerDown={(event) => {
                    if (!isRenaming && state !== "saving") {
                      startTriggerPointerDrag(event, trigger);
                    }
                  }}
                  title="Drag into a loop graph"
                >
                  <LoopspaceTriggerRowHeader>
                    <LoopspaceTriggerTypeIconTile data-kind={trigger.type}>
                      <TypeIcon aria-hidden="true" />
                    </LoopspaceTriggerTypeIconTile>
                    <LoopspaceTriggerNameControl>
                      <LoopspaceTriggerNameInput
                        aria-label="Trigger name"
                        maxLength={120}
                        onChange={(event) => {
                          setNameDrafts((current) => ({
                            ...current,
                            [trigger.id]: event.target.value,
                          }));
                        }}
                        onDoubleClick={() => beginRenameTrigger(trigger)}
                        onKeyDown={(event) => {
                          if (!isRenaming) {
                            return;
                          }
                          if (event.key === "Enter") {
                            event.preventDefault();
                            renameTrigger(trigger);
                          } else if (event.key === "Escape") {
                            event.preventDefault();
                            cancelRenameTrigger(trigger);
                          }
                        }}
                        readOnly={!isRenaming}
                        ref={isRenaming ? editingNameInputRef : null}
                        title={isRenaming ? "Editing trigger name" : "Click the pencil to rename"}
                        value={nameDrafts[trigger.id] ?? trigger.name}
                      />
                      <LoopspaceTriggerNameEditButton
                        aria-label={isRenaming ? "Save trigger name" : "Rename trigger"}
                        data-active={isRenaming ? "true" : undefined}
                        disabled={state === "saving"}
                        onClick={() => (isRenaming ? renameTrigger(trigger) : beginRenameTrigger(trigger))}
                        title={isRenaming ? "Save name" : "Rename"}
                        type="button"
                      >
                        {isRenaming ? <Check aria-hidden="true" /> : <Edit aria-hidden="true" />}
                      </LoopspaceTriggerNameEditButton>
                    </LoopspaceTriggerNameControl>
                    <LoopspaceTriggerActionRow>
                      {trigger.type === "manual" ? (
                        <LoopspaceTriggerIconButton
                          aria-label="Run trigger"
                          disabled={state === "saving" || !trigger.enabled}
                          onClick={() => runTrigger(trigger)}
                          title="Run"
                          type="button"
                        >
                          <PlayArrow aria-hidden="true" />
                        </LoopspaceTriggerIconButton>
                      ) : null}
                      {trigger.type === "webhook" && webhookUrl ? (
                        <>
                          <LoopspaceTriggerIconButton
                            aria-label="Copy webhook URL"
                            data-copied={isWebhookCopied ? "true" : undefined}
                            onClick={() => copyWebhookTrigger(trigger, webhookUrl)}
                            title={isWebhookCopied ? "Copied" : "Copy webhook URL"}
                            type="button"
                          >
                            <ContentCopy aria-hidden="true" />
                          </LoopspaceTriggerIconButton>
                          {trigger.webhook_auth_mode !== "public_token" && trigger.webhook_secret ? (
                            <LoopspaceTriggerIconButton
                              aria-label="Copy webhook signing secret"
                              data-copied={isWebhookSecretCopied ? "true" : undefined}
                              onClick={() => copyWebhookSecret(trigger)}
                              title={isWebhookSecretCopied ? "Copied" : "Copy signing secret"}
                              type="button"
                            >
                              <ContentCopy aria-hidden="true" />
                            </LoopspaceTriggerIconButton>
                          ) : null}
                          <LoopspaceTriggerIconButton
                            aria-label="Rotate webhook secret"
                            disabled={state === "saving"}
                            onClick={() => rotateWebhookSecret(trigger)}
                            title={trigger.webhook_auth_mode === "public_token" ? "Rotate public URL token" : "Rotate signing secret"}
                            type="button"
                          >
                            <ButtonRefreshIcon aria-hidden="true" />
                          </LoopspaceTriggerIconButton>
                        </>
                      ) : null}
                      <LoopspaceTriggerIconButton
                        aria-label={trigger.enabled ? "Disable trigger" : "Enable trigger"}
                        data-active={trigger.enabled ? "true" : undefined}
                        disabled={state === "saving"}
                        onClick={() => toggleTriggerEnabled(trigger)}
                        title={trigger.enabled ? "Disable" : "Enable"}
                        type="button"
                      >
                        {trigger.enabled ? <ToggleOn aria-hidden="true" /> : <ToggleOff aria-hidden="true" />}
                      </LoopspaceTriggerIconButton>
                      <LoopspaceTriggerIconButton
                        aria-label="Delete trigger"
                        disabled={state === "saving"}
                        onClick={() => deleteTrigger(trigger)}
                        title="Delete"
                        type="button"
                      >
                        <Close aria-hidden="true" />
                      </LoopspaceTriggerIconButton>
                    </LoopspaceTriggerActionRow>
                  </LoopspaceTriggerRowHeader>
                  <LoopspaceTriggerBadgeRow>
                    <LoopspaceTriggerBadge>
                      {getLoopspaceTriggerTypeLabel(trigger.type)}
                    </LoopspaceTriggerBadge>
                    <LoopspaceTriggerBadge data-tone={trigger.enabled ? "good" : "muted"}>
                      {trigger.enabled ? "Enabled" : "Disabled"}
                    </LoopspaceTriggerBadge>
                    {trigger.type === "webhook" ? (
                      <LoopspaceTriggerBadge data-tone={trigger.webhook_auth_mode === "public_token" ? "risk" : "good"}>
                        {getLoopspaceWebhookAuthLabel(trigger.webhook_auth_mode)}
                      </LoopspaceTriggerBadge>
                    ) : null}
                    {trigger.type === "cron" && trigger.config?.schedule ? (
                      <LoopspaceTriggerBadge>{trigger.config.schedule}</LoopspaceTriggerBadge>
                    ) : null}
                    {attachedLoops.length ? (
                      <LoopspaceTriggerBadge>{attachedLoops.join(", ")}</LoopspaceTriggerBadge>
                    ) : null}
                    {nextDue ? <LoopspaceTriggerBadge>{`Next ${nextDue}`}</LoopspaceTriggerBadge> : null}
                    {lastRun ? <LoopspaceTriggerBadge>{`Last ${lastRun}`}</LoopspaceTriggerBadge> : null}
                    {trigger.last_status ? <LoopspaceTriggerBadge>{trigger.last_status}</LoopspaceTriggerBadge> : null}
                  </LoopspaceTriggerBadgeRow>
                  {trigger.webhook_path ? (
                    <LoopspaceTriggerWebhookPath title={webhookUrl || trigger.webhook_path}>
                      {webhookUrl || trigger.webhook_path}
                      {trigger.webhook_auth_mode !== "public_token" && trigger.webhook_secret_hint
                        ? ` · secret ${trigger.webhook_secret_hint}`
                        : ""}
                    </LoopspaceTriggerWebhookPath>
                  ) : null}
                </LoopspaceTriggerRow>
              );
            })}
          </LoopspaceTriggerList>
        ) : (
          <LoopspaceTriggerEmpty>No triggers</LoopspaceTriggerEmpty>
        )}
      </LoopspaceTriggersScroll>
    </LoopspaceTriggersView>
  );
});

const TodoQueueComposer = styled.form`
  position: relative;
  display: block;
  width: 100%;
  min-width: 0;
  min-height: 35px;
  flex: 0 0 auto;

  /* A dragged snip preview window or OS file is hovering the draft area:
     dropping creates a new (uncreated) todo carrying the attachment. */
  &[data-snip-drop-active="true"] {
    border-radius: 8px;
    background: rgba(74, 222, 128, 0.12);
    box-shadow: inset 0 0 0 1.5px rgba(74, 222, 128, 0.6);
  }

  &[data-drop-flash="true"]::after {
    content: "";
    position: absolute;
    inset: 0;
    border-radius: 8px;
    pointer-events: none;
    box-shadow:
      inset 0 0 0 1.5px rgba(74, 222, 128, 0.9),
      inset 0 0 18px rgba(74, 222, 128, 0.3);
    animation: ${todoDropAcceptFlash} 900ms ease-out forwards;
  }
`;

